from typing import List
from collections import deque, defaultdict
import random


class Solution:
    def numBusesToDestination(self, routes: List[List[int]], source: int, target: int) -> int:
        if source == target:
            return 0

        stop_to_buses = defaultdict(list)
        for bus_id, route in enumerate(routes):
            for stop in route:
                stop_to_buses[stop].append(bus_id)

        if source not in stop_to_buses:
            return -1

        visited_buses = set()
        queue = deque()
        for bus_id in stop_to_buses[source]:
            queue.append(bus_id)
            visited_buses.add(bus_id)

        buses_taken = 1
        route_sets = [set(r) for r in routes]

        while queue:
            for _ in range(len(queue)):
                bus_id = queue.popleft()
                if target in route_sets[bus_id]:
                    return buses_taken
                for stop in routes[bus_id]:
                    for next_bus in stop_to_buses[stop]:
                        if next_bus not in visited_buses:
                            visited_buses.add(next_bus)
                            queue.append(next_bus)
                    stop_to_buses[stop] = []  # clear: stop never useful again
            buses_taken += 1

        return -1


# ---- brute force oracle: BFS over (stop) tracking buses boarded via state ----
def brute(routes, source, target):
    if source == target:
        return 0
    from collections import defaultdict, deque
    stop_buses = defaultdict(set)
    for i, r in enumerate(routes):
        for s in r:
            stop_buses[s].add(i)
    # BFS where state = stop, level = buses taken to reach it
    # start: stops reachable by boarding any bus at source
    visited_stops = set([source])
    q = deque([source])
    buses = 0
    # board a bus = move to all stops on buses that contain current frontier
    frontier_buses_used = set()
    # simpler: BFS over buses identical logic but independent impl
    visited_b = set()
    q2 = deque()
    for b in stop_buses[source]:
        q2.append(b); visited_b.add(b)
    lvl = 1
    while q2:
        for _ in range(len(q2)):
            b = q2.popleft()
            if target in routes[b]:
                return lvl
            for s in routes[b]:
                for nb in stop_buses[s]:
                    if nb not in visited_b:
                        visited_b.add(nb); q2.append(nb)
        lvl += 1
    return -1


def test():
    sol = Solution()
    cases = [
        ([[1,2,7],[3,6,7]], 1, 6, 2),
        ([[7,12],[4,5,15],[6],[15,19],[9,12,13]], 15, 12, -1),
        ([[1,2,7],[3,6,7]], 1, 1, 0),
        ([[1,7],[3,5]], 5, 5, 0),
        ([[2]], 2, 2, 0),
        ([[1,2,3]], 1, 3, 1),
        ([[1,2,3]], 1, 4, -1),
        ([], 1, 2, -1) if False else ([[1]], 1, 2, -1),
    ]
    for routes, s, t, exp in cases:
        got = sol.numBusesToDestination([list(r) for r in routes], s, t)
        assert got == exp, f"FAIL {routes} {s}->{t}: got {got} exp {exp}"
    print("fixed cases passed")

    # random vs oracle
    for _ in range(3000):
        n = random.randint(1, 6)
        routes = []
        for _ in range(n):
            sz = random.randint(1, 4)
            routes.append(random.sample(range(0, 8), sz))
        s = random.randint(0, 7)
        t = random.randint(0, 7)
        a = sol.numBusesToDestination([list(r) for r in routes], s, t)
        b = brute([list(r) for r in routes], s, t)
        assert a == b, f"MISMATCH {routes} {s}->{t}: sol {a} brute {b}"
    print("random vs oracle passed")


if __name__ == "__main__":
    test()
